class Solution:
    def solveEquation(self, equation: str) -> str:
        left, right = equation.split('=')
        left_x, left_const = self.parse_expression(left)
        right_x, right_const = self.parse_expression(right)
        coeff_x = left_x - right_x
        const = right_const - left_const

        if coeff_x == 0:
            if const == 0:
                return "Infinite solutions"
            else:
                return "No solution"
        else:
            return f"x={const // coeff_x}"

    def parse_expression(self, expression: str) -> tuple:
        x_coeff = 0
        const = 0
        sign = 1
        num = 0
        for i, char in enumerate(expression):
            if char == '+':
                const += sign * num
                num = 0
                sign = 1
            elif char == '-':
                const += sign * num
                num = 0
                sign = -1
            elif char == 'x':
                if num == 0:
                    x_coeff += sign
                else:
                    x_coeff += sign * num
                num = 0
            else:
                num = num * 10 + int(char)
        const += sign * num
        return x_coeff, const

